// Helper to parse response or fallback to mock offline status if node failed
function getHealth(nodeName, module_id, module_name, local_base_url, default_endpoints) {
  let res = null;
  try {
    res = $node[nodeName].json;
  } catch (e) {}

  if (res && res.status && !res.error) {
    return {
      module_id: res.module_id || module_id,
      module_name: res.module_name || module_name,
      status: res.status,
      mode: res.mode || "local_stub",
      version: res.version || "1.0.0",
      uptime_mock: res.uptime_mock || 3600,
      local_base_url: res.local_base_url || local_base_url,
      endpoints: res.endpoints || default_endpoints,
      last_checked_at: new Date().toISOString(),
      source: res.source || (module_id + "_stub"),
      notes: res.notes || "Healthy"
    };
  } else {
    // Fallback: unavailable if connection refused / node failed
    return {
      module_id: module_id,
      module_name: module_name,
      status: "unavailable",
      mode: "local_stub",
      version: "1.0.0",
      uptime_mock: 0,
      local_base_url: local_base_url,
      endpoints: default_endpoints,
      last_checked_at: new Date().toISOString(),
      source: module_id + "_stub",
      notes: "Local stub unavailable (connection refused)."
    };
  }
}

const modulesHealth = [
  getHealth("HTTP: ComfyUI Health", "creative_asset_comfyui", "ComfyUI Image Generation Pipeline", "http://localhost:8188", ["GET /health", "POST /run"]),
  getHealth("HTTP: Content Health", "content_pack_generator", "Social Content Pack Generator Stub", "http://localhost:8191", ["GET /health", "POST /run"]),
  getHealth("HTTP: Ads Health", "ads_pack_generator", "Advertising Creative Pack Generator Stub", "http://localhost:8192", ["GET /health", "POST /run"]),
  getHealth("HTTP: CRM Health", "crm_followup_generator", "CRM Sequence Draft Generator Stub", "http://localhost:8193", ["GET /health", "POST /run"]),
  getHealth("HTTP: Analytics Health", "analytics_report_generator", "Performance Analytics Report Stub", "http://localhost:8194", ["GET /health", "POST /run"])
];

return [{
  json: {
    modules: modulesHealth
  }
}];

const input = items[0].json;
const modules = input.modules;

let healthy_count = 0;
let degraded_count = 0;
let unavailable_count = 0;
let unknown_count = 0;
const blocking_modules = [];

modules.forEach(m => {
  if (m.status === "healthy") {
    healthy_count++;
  } else if (m.status === "degraded") {
    degraded_count++;
  } else if (m.status === "unavailable") {
    unavailable_count++;
    // In this business logic, creative_asset_comfyui and analytics_report_generator are blocking modules
    if (["creative_asset_comfyui", "analytics_report_generator"].includes(m.module_id)) {
      blocking_modules.push(m.module_id);
    }
  } else {
    unknown_count++;
  }
});

let overall_status = "healthy";
let readiness_status = "ready_for_mock_run";
let notes = "All modules online. System fully ready.";

if (blocking_modules.length > 0) {
  overall_status = "unavailable";
  readiness_status = "blocked";
  notes = `Critical modules unavailable (${blocking_modules.join(", ")}). Router execution blocked.`;
} else if (degraded_count > 0 || unavailable_count > 0) {
  overall_status = "degraded";
  readiness_status = "partially_ready";
  notes = "Non-blocking module degraded or unavailable. System remains partially ready.";
}

return [{
  json: {
    contract_version: "module_health_check_v0.1",
    overall_status: overall_status,
    checked_at: new Date().toISOString(),
    modules: modules.map(m => ({
      module_id: m.module_id,
      status: m.status,
      endpoint: m.local_base_url + "/health"
    })),
    healthy_count: healthy_count,
    degraded_count: degraded_count,
    unavailable_count: unavailable_count,
    unknown_count: unknown_count,
    readiness_status: readiness_status,
    blocking_modules: blocking_modules,
    source: "n8n_n10_module_health_check_mock",
    notes: notes,
    full_modules_details: modules
  }
}];

const agg = items[0].json;
const details = agg.full_modules_details;

const warnings = [];
const next_actions = [];

details.forEach(d => {
  if (d.status === "degraded") {
    warnings.push(`${d.module_id} has degraded performance.`);
    next_actions.push(`Verify ${d.module_id} local stub network lag.`);
  } else if (d.status === "unavailable") {
    warnings.push(`${d.module_id} is unreachable.`);
    next_actions.push(`Start ${d.module_id} stub server (node modules/${d.module_id === "creative_asset_comfyui" ? "comfyui-pipeline/src" : d.module_id.replace(/_/g, "-")}/server.js).`);
  }
});

if (warnings.length === 0) {
  next_actions.push("No action needed. Ready to run.");
}

const dashboard_data = {
  dashboard_id: "dash_" + Math.random().toString(36).substring(2, 9),
  generated_at: new Date().toISOString(),
  overall_status: agg.overall_status,
  cards: {
    total_modules: details.length,
    healthy_count: agg.healthy_count,
    degraded_count: agg.degraded_count,
    unavailable_count: agg.unavailable_count,
    unknown_count: agg.unknown_count,
    readiness_summary: agg.readiness_status === "blocked"
      ? "System blocked. Critical modules are offline."
      : (agg.readiness_status === "partially_ready" ? "System partially ready. Non-critical stubs degraded." : "System fully ready for mock campaign processing.")
  },
  module_table: details.map(d => ({
    module_id: d.module_id,
    module_name: d.module_name,
    status: d.status,
    uptime: d.uptime_mock + "s",
    endpoint: d.local_base_url + "/health"
  })),
  warnings: warnings,
  next_actions: next_actions,
  source: "n8n_n10_module_health_check_mock",
  notes: agg.overall_status + " dashboard render."
};

return [{
  json: {
    contract_version: agg.contract_version,
    overall_status: agg.overall_status,
    readiness_status: agg.readiness_status,
    modules: agg.modules,
    blocking_modules: agg.blocking_modules,
    dashboard_data: dashboard_data,
    source: "n8n_n10_module_health_check_mock",
    notes: agg.notes
  }
}];
